import '../models/program_day.dart';

const List<ProgramDay> programDays = [
  ProgramDay(day: 1, title: 'Jour de prise de conscience', tip: 'Remarquez chaque fois que vous portez votre main à votre bouche aujourd\'hui sans vous juger.', exercise: 'Portez un élastique au poignet. Chaque fois que vous ressentez l\'envie, faites-le claquer doucement.'),
  ProgramDay(day: 2, title: 'Cartographie des déclencheurs', tip: 'La morsure des ongles est souvent déclenchée par le stress, l\'ennui ou la concentration. Aujourd\'hui, identifiez votre déclencheur n°1.', exercise: 'Gardez un petit carnet. Notez la situation chaque fois que vous vous mordez.'),
  ProgramDay(day: 3, title: 'Réponse concurrente', tip: 'Remplacez la morsure des ongles par un comportement concurrent : serrez le poing pendant 60 secondes.', exercise: 'Pratiquez le serrement de poing 10 fois aujourd\'hui, même sans l\'envie.'),
  ProgramDay(day: 4, title: 'Aménagement de l\'environnement', tip: 'Réduisez l\'accès : appliquez un vernis à ongles au goût amer ou gardez des gants à portée de main.', exercise: 'Identifiez 3 environnements où vous vous mordez le plus et planifiez une réponse concurrente spécifique pour chacun.'),
  ProgramDay(day: 5, title: 'Mains conscientes', tip: 'Vos mains font des choses extraordinaires. Concentrez-vous sur ce qu\'elles créent, pas sur ce qu\'elles détruisent.', exercise: 'Passez 5 minutes à faire un rituel de soin des mains : lavez, hydratez, observez vos ongles.'),
  ProgramDay(day: 6, title: 'Surfer sur l\'envie', tip: 'Une envie est comme une vague : elle monte, atteint son sommet et passe. Vous n\'êtes pas obligé d\'y céder.', exercise: 'La prochaine fois que l\'envie se présente, réglez une minuterie de 2 minutes et observez simplement la sensation.'),
  ProgramDay(day: 7, title: 'Bilan de la semaine 1', tip: 'Vous avez tenu toute une semaine ! Réfléchissez à vos déclencheurs et à vos victoires.', exercise: 'Notez vos 3 plus grands déclencheurs et 1 succès de cette semaine.'),
  ProgramDay(day: 8, title: 'Libération du stress', tip: 'Le stress est le déclencheur n°1 de la morsure des ongles. Construisez une micro-habitude de libération du stress.', exercise: 'Pratiquez la respiration carrée : inspirez 4s, retenez 4s, expirez 4s, retenez 4s. Répétez 4 fois.'),
  ProgramDay(day: 9, title: 'Conscience sociale', tip: 'Vous mordez-vous plus en parlant aux autres ou seul ? Observez aujourd\'hui.', exercise: 'Dans votre prochaine conversation, gardez consciemment les mains sur les genoux ou sur une table.'),
  ProgramDay(day: 10, title: 'Système de récompense', tip: 'Le renforcement positif fonctionne. Célébrez les petites victoires.', exercise: 'Si vous arrivez à ce soir sans morsure, offrez-vous quelque chose de petit que vous appréciez.'),
  ProgramDay(day: 11, title: 'Substitut sensoriel', tip: 'Vos doigts ont besoin de stimulation. Donnez-leur autre chose.', exercise: 'Gardez un anneau fidget, une balle anti-stress ou une pierre lisse dans votre poche aujourd\'hui.'),
  ProgramDay(day: 12, title: 'Le POURQUOI', tip: 'Connectez-vous à votre "pourquoi" : Des ongles plus sains ? Confiance en soi ? Autre chose ?', exercise: 'Écrivez votre "pourquoi" sur un post-it et mettez-le quelque part de visible.'),
  ProgramDay(day: 13, title: 'Visualisation', tip: 'La répétition mentale est aussi puissante que la pratique physique.', exercise: 'Passez 3 minutes à vous imaginer remarquer l\'envie et choisir calmement votre réponse concurrente.'),
  ProgramDay(day: 14, title: '2 semaines de force', tip: 'Les voies neuronales mettent ~21 jours pour commencer à changer. Vous êtes aux 2/3 !', exercise: 'Prenez une photo de vos ongles et comparez au jour 1. Notez toute amélioration.'),
  ProgramDay(day: 15, title: 'Combattre l\'ennui', tip: 'La morsure par ennui est réelle. Ayez une activité de secours prête.', exercise: 'Listez 3 activités rapides (moins de 2 min) que vous pouvez faire au lieu de vous mordre quand vous vous ennuyez.'),
  ProgramDay(day: 16, title: 'Investissement dans les soins des ongles', tip: 'Quand vos ongles sont beaux, vous êtes moins susceptible de les mordre.', exercise: 'Limez et nettoyez vos ongles aujourd\'hui. L\'investissement vous donnera envie de les protéger.'),
  ProgramDay(day: 17, title: 'Sommeil et habitudes', tip: 'Un mauvais sommeil augmente le stress et affaiblit le contrôle des habitudes. Priorisez le repos.', exercise: 'Fixez un coucher 30 minutes plus tôt ce soir et évitez les écrans 1 heure avant de dormir.'),
  ProgramDay(day: 18, title: 'Responsabilité', tip: 'Dire à quelqu\'un votre objectif double vos chances de succès.', exercise: 'Partagez votre objectif avec une personne de confiance aujourd\'hui.'),
  ProgramDay(day: 19, title: 'Scan corporel', tip: 'La tension dans votre corps entraîne souvent la morsure des ongles.', exercise: 'Faites un scan corporel de 5 minutes : remarquez où vous tenez la tension et relâchez-la consciemment.'),
  ProgramDay(day: 20, title: 'Jalon de progression', tip: '20 jours ! Vous construisez une nouvelle identité : quelqu\'un qui prend soin de ses mains.', exercise: 'Passez en revue votre journal de morsures. À quel moment de la journée vous mordez-vous le plus ? Planifiez une vigilance accrue pour cette fenêtre.'),
  ProgramDay(day: 21, title: 'Marque des 21 jours', tip: 'La recherche montre que 21 jours est le début du changement d\'habitude. L\'élan se construit !', exercise: 'Écrivez une courte lettre à votre futur moi sur ce que la vie ressemble avec des ongles plus sains.'),
  ProgramDay(day: 22, title: 'Déclencheurs travail/écran', tip: 'Beaucoup de personnes se mordent pendant le travail sur ordinateur ou le défilement. Mettez des barrières en place.', exercise: 'Mettez un post-it sur votre moniteur : "Mains visibles = mains en sécurité."'),
  ProgramDay(day: 23, title: 'Hydratation et ongles', tip: 'La déshydratation rend les ongles cassants et la peau rugueuse — augmentant l\'envie de mordre.', exercise: 'Buvez 2L d\'eau aujourd\'hui et appliquez de la crème pour les mains matin et soir.'),
  ProgramDay(day: 24, title: 'Restructuration cognitive', tip: 'Remettez en question la pensée "juste une petite morsure". Ce n\'est jamais juste une.', exercise: 'Quand la pensée apparaît, contre-argumentez : "Cette envie passera en moins de 3 minutes."'),
  ProgramDay(day: 25, title: 'Médias sociaux et mains', tip: 'Le défilement est un déclencheur majeur. Rendez votre téléphone plus difficile d\'accès.', exercise: 'Mettez votre téléphone en niveaux de gris pendant une heure aujourd\'hui pour réduire le défilement sans réfléchir.'),
  ProgramDay(day: 26, title: 'L\'astuce de la lime à ongles', tip: 'Les bords rugueux déclenchent la morsure. Portez une lime à ongles et utilisez-la à la place.', exercise: 'Gardez une lime à ongles dans votre sac, sur votre bureau et sur votre table de chevet.'),
  ProgramDay(day: 27, title: 'Régulation émotionnelle', tip: 'La morsure des ongles apaise souvent l\'anxiété. Construisez une boîte à outils d\'apaisants sains.', exercise: 'Listez 5 choses qui vous calment : musique, une promenade, thé, respiration, étirements.'),
  ProgramDay(day: 28, title: '4 semaines !', tip: 'Quatre semaines de prise de conscience et d\'efforts. Un vrai changement se produit sous la surface.', exercise: 'Comparez la photo de vos ongles d\'aujourd\'hui à la semaine 1. Notez ce que vous observez.'),
  ProgramDay(day: 29, title: 'Changement d\'identité', tip: 'Commencez à dire "Je suis quelqu\'un qui ne se ronge pas les ongles" au lieu de "J\'essaie d\'arrêter."', exercise: 'Utilisez cette phrase 3 fois aujourd\'hui, à voix haute ou intérieurement.'),
  ProgramDay(day: 30, title: 'Jalon des 30 jours', tip: 'Un mois ! Les voies neuronales sont en train d\'être recâblées.', exercise: 'Célébrez de manière significative. Quelle récompense avez-vous prévue au début ?'),
  ProgramDay(day: 31, title: 'Récupération après une rechute', tip: 'Glisser fait partie du processus. Ce qui compte, c\'est de se remettre sur la bonne voie immédiatement.', exercise: 'Si vous avez eu des revers, écrivez ce qui les a déclenchés et un ajustement que vous ferez.'),
  ProgramDay(day: 32, title: 'Routine matinale', tip: 'Un bon matin donne le ton pour la journée.', exercise: 'Ajoutez une vérification des ongles de 30 secondes à votre routine matinale : observez, hydratez, fixez votre intention.'),
  ProgramDay(day: 33, title: 'Détente du soir', tip: 'Le stress du soir déclenche souvent la morsure. Construisez un rituel apaisant.', exercise: 'Pendant les 7 prochains jours, faites 5 min d\'étirements avant de dormir.'),
  ProgramDay(day: 34, title: 'La pause', tip: 'Créez une pause entre l\'envie et l\'action. Même 5 secondes aident.', exercise: 'Pratiquez en vous disant : "Je remarque l\'envie. Je choisis ma réponse."'),
  ProgramDay(day: 35, title: 'Alimentation consciente', tip: 'Les mains près de votre visage pendant les repas peuvent déclencher l\'habitude.', exercise: 'Mangez un repas aujourd\'hui lentement, avec toute votre attention, les mains ne touchant que les ustensiles.'),
  ProgramDay(day: 36, title: 'Confiance et ongles', tip: 'Comment vos ongles vous font-ils sentir ? Laissez votre réponse vous motiver.', exercise: 'Peignez un ongle d\'une couleur que vous aimez (n\'importe quelle option neutre en genre fonctionne).'),
  ProgramDay(day: 37, title: 'Empilement des habitudes', tip: 'Attachez votre réponse concurrente à une habitude existante.', exercise: 'Chaque fois que vous préparez du café/thé aujourd\'hui, faites un étirement des mains de 10 secondes au lieu de vous mordre.'),
  ProgramDay(day: 38, title: 'Protection du travail profond', tip: 'Les tâches de concentration sont à haut risque. Préparez-vous pour le succès.', exercise: 'Mettez des gants fins ou du ruban adhésif sur vos doigts pendant votre prochaine session de travail profond.'),
  ProgramDay(day: 39, title: 'Gratitude pour les mains', tip: 'Vos mains permettent tout ce que vous créez.', exercise: 'Écrivez 5 choses que vos mains vous ont aidé à faire aujourd\'hui.'),
  ProgramDay(day: 40, title: 'À mi-chemin !', tip: 'Jour 40 sur 90 — vous êtes presque à mi-chemin. C\'est remarquable.', exercise: 'Prenez une photo complète de vos mains et notez comment votre relation avec cette habitude a changé.'),
  ProgramDay(day: 41, title: 'Morsure pendant le sommeil', tip: 'Certaines personnes se mordent pendant leur sommeil. Envisagez des gants la nuit si cela vous concerne.', exercise: 'Vérifiez vos ongles chaque matin pour voir si la morsure pendant le sommeil est un facteur.'),
  ProgramDay(day: 42, title: 'Protéines et ongles', tip: 'Des ongles forts ont besoin de protéines et de biotine. L\'alimentation compte.', exercise: 'Recherchez 3 aliments riches en biotine et ajoutez-en un à votre prochain repas.'),
  ProgramDay(day: 43, title: 'La technique 5-4-3-2-1', tip: 'L\'ancrage brise instantanément le cycle anxiété-morsure.', exercise: 'Quand l\'envie frappe : nommez 5 choses que vous voyez, 4 que vous entendez, 3 que vous pouvez toucher, 2 que vous sentez, 1 que vous goûtez.'),
  ProgramDay(day: 44, title: 'Temps d\'écran et envies', tip: 'Faire défiler avec une main pendant que l\'autre est inactive = zone dangereuse.', exercise: 'Tenez quelque chose dans votre main libre en utilisant votre téléphone aujourd\'hui.'),
  ProgramDay(day: 45, title: 'Bilan à mi-programme', tip: '45 jours : réfléchissez à votre parcours. Qu\'est-ce qui est devenu plus facile ? Plus difficile ?', exercise: 'Rédigez une courte réflexion à mi-programme. Partagez-la avec votre partenaire de responsabilité si vous en avez un.'),
  ProgramDay(day: 46, title: 'Le journal comme prévention', tip: 'Écrire sur le stress réduit l\'envie de se consoler en mordant.', exercise: 'Passez 5 minutes à écrire librement sur tout ce qui vous passe par la tête en ce moment.'),
  ProgramDay(day: 47, title: 'Exercice physique', tip: 'L\'exercice régulier réduit l\'anxiété de base et l\'envie de se mordre.', exercise: 'Faites 20 minutes de toute activité physique aujourd\'hui.'),
  ProgramDay(day: 48, title: 'Ongles propres = ongles plus sûrs', tip: 'Les ongles propres et limés sans bords rugueux sont beaucoup moins tentants.', exercise: 'Faites une session complète d\'entretien des ongles aujourd\'hui.'),
  ProgramDay(day: 49, title: '7 semaines !', tip: 'Sept semaines à construire une nouvelle relation avec vos mains.', exercise: 'Comparez les photos des semaines 1, 4 et 7. Notez ce que vous observez.'),
  ProgramDay(day: 50, title: 'Audit des habitudes', tip: 'Qu\'est-ce qui fonctionne ? Qu\'est-ce qui doit être ajusté dans votre approche ?', exercise: 'Passez en revue les modèles de votre journal de morsures. Ajustez une stratégie en fonction des données.'),
  ProgramDay(day: 51, title: 'Le pouvoir du non', tip: 'Pratiquez à dire non à l\'envie comme vous le feriez pour toute distraction.', exercise: 'Dites "pas maintenant" à voix haute la prochaine fois que l\'envie apparaît.'),
  ProgramDay(day: 52, title: 'Massage des mains', tip: 'Un massage des mains interrompt le réflexe de morsure et est gratifiant.', exercise: 'Faites-vous un massage des mains de 3 minutes avec de la lotion avant de vous coucher ce soir.'),
  ProgramDay(day: 53, title: 'La musique comme ancre', tip: 'Une chanson spécifique peut devenir une ancre qui brise l\'état de morsure.', exercise: 'Choisissez votre "chanson d\'interruption" — jouez-la chaque fois que vous ressentez l\'envie.'),
  ProgramDay(day: 54, title: 'Responsabilité publique', tip: 'Les progrès partagés sont des progrès multipliés.', exercise: 'Publiez sur votre défi (anonymement si nécessaire) dans une communauté de bien-être.'),
  ProgramDay(day: 55, title: 'Lettre à votre futur moi', tip: 'Votre futur moi avec des ongles sains est réel. Écrivez-lui.', exercise: 'Écrivez une lettre de votre moi du jour 90 à votre moi d\'aujourd\'hui.'),
  ProgramDay(day: 56, title: '8 semaines de force', tip: 'Deux mois ! Vos ongles ont eu 8 semaines de temps de récupération.', exercise: 'Célébrez avec un petit rituel de soin personnel : un bain, un bon repas, une promenade.'),
  ProgramDay(day: 57, title: 'Défusion cognitive', tip: 'Les pensées ne sont que des pensées. "Je veux mordre" ≠ "Je vais mordre."', exercise: 'Quand la pensée d\'envie apparaît, dites : "J\'ai la pensée que je veux mordre." Puis laissez-la passer.'),
  ProgramDay(day: 58, title: 'Collations saines', tip: 'Une glycémie basse déclenche le stress et l\'impulsivité, y compris la morsure.', exercise: 'Mangez une petite collation saine à 15h pour éviter le creux de fin d\'après-midi.'),
  ProgramDay(day: 59, title: 'Acceptation', tip: 'Acceptez que les envies viendront, sans les combattre. Les combattre crée de la tension.', exercise: 'Pratiquez l\'acceptation de l\'envie : "Je la ressens, je la reconnais, je la laisse passer."'),
  ProgramDay(day: 60, title: 'Jalon des 60 jours !', tip: 'Aux deux tiers. Vos schémas d\'habitudes sont significativement perturbés maintenant.', exercise: 'Prenez rendez-vous pour une manucure ou un soin des ongles comme récompense.'),
  ProgramDay(day: 61, title: 'L\'effet composé', tip: 'Les petites actions quotidiennes s\'accumulent en un changement massif sur 90 jours.', exercise: 'Calculez : si vous aviez 10 morsures/jour avant, combien en avez-vous évité ce mois-ci ?'),
  ProgramDay(day: 62, title: 'Qualité du sommeil', tip: 'Mauvais sommeil = volonté faible. Faites du sommeil une priorité cette semaine.', exercise: 'Passez en revue votre horaire de sommeil. Visez 7-8 heures ce soir.'),
  ProgramDay(day: 63, title: '9 semaines !', tip: 'Neuf semaines de choix différents.', exercise: 'Notez 3 choses qui sont plus faciles maintenant qu\'au jour 1.'),
  ProgramDay(day: 64, title: 'Alignement des valeurs', tip: 'La morsure correspond-elle à qui vous voulez être ? Laissez vos valeurs vous guider.', exercise: 'Listez 3 valeurs personnelles fondamentales et comment des ongles plus sains est lié à chacune.'),
  ProgramDay(day: 65, title: 'La règle des 2 minutes', tip: 'Si l\'envie frappe, attendez juste 2 minutes. 2 minutes est toujours possible.', exercise: 'Pratiquez le délai de 2 minutes 3 fois aujourd\'hui, avec ou sans envie.'),
  ProgramDay(day: 66, title: 'Comparaison de photos', tip: 'La preuve visuelle du progrès est l\'un des motivateurs les plus forts.', exercise: 'Alignez vos photos hebdomadaires. La tendance devrait être visible maintenant.'),
  ProgramDay(day: 67, title: 'Réinitialisation respiratoire', tip: 'La respiration lente active instantanément le système nerveux parasympathique.', exercise: 'Respiration 4-7-8 : inspirez 4s, retenez 7s, expirez 8s. Faites cela 3 fois quand vous êtes stressé.'),
  ProgramDay(day: 68, title: 'Protection de la série sans morsure', tip: 'Si vous êtes sur une série, protégez-la. La série elle-même devient une motivation.', exercise: 'Vérifiez vos analyses. Si vous avez une série, notez-la et engagez-vous pour un jour de plus.'),
  ProgramDay(day: 69, title: 'Enseigner aux autres', tip: 'Expliquer le changement d\'habitude aux autres consolide votre propre compréhension.', exercise: 'Expliquez la technique de renversement d\'habitude à quelqu\'un qui pourrait en bénéficier.'),
  ProgramDay(day: 70, title: '70 jours !', tip: '70 jours. Vous avez construit quelque chose de réel.', exercise: 'Notez votre leçon n°1 apprise dans ce parcours jusqu\'à présent.'),
  ProgramDay(day: 71, title: 'Guerriers du week-end', tip: 'Beaucoup de personnes se mordent davantage les week-ends en raison du temps non structuré.', exercise: 'Planifiez votre week-end avec des activités qui gardent vos mains occupées et votre esprit engagé.'),
  ProgramDay(day: 72, title: 'Affirmations', tip: 'Le discours intérieur positif reshape la perception de soi.', exercise: 'Créez 3 affirmations personnelles sur vos mains et répétez-les matin et soir.'),
  ProgramDay(day: 73, title: 'Routine de renforcement des ongles', tip: 'La biotine, la vitamine E et l\'hydratation renforcent les ongles de l\'intérieur.', exercise: 'Appliquez de l\'huile de vitamine E ou de l\'huile pour cuticules sur vos ongles ce soir.'),
  ProgramDay(day: 74, title: 'La grande image', tip: 'Ce n\'est pas seulement une question d\'ongles. Il s\'agit de vous prouver que vous pouvez changer n\'importe quelle habitude.', exercise: 'Quelle autre habitude aimeriez-vous changer ensuite ? Notez-la.'),
  ProgramDay(day: 75, title: 'À 75% !', tip: '75 jours ! Les trois quarts du parcours sont accomplis.', exercise: 'Prenez une photo soigneuse de vos 10 ongles. Comparez au jour 1. Incroyable, n\'est-ce pas ?'),
  ProgramDay(day: 76, title: 'État d\'esprit de maintenance', tip: 'Après 90 jours, vous aurez besoin d\'un plan de maintenance. Commencez à y réfléchir maintenant.', exercise: 'Rédigez vos habitudes de maintenance post-programme (3 actions clés à maintenir).'),
  ProgramDay(day: 77, title: '11 semaines !', tip: 'Onze semaines de vie intentionnelle.', exercise: 'Identifiez votre outil de combat contre les habitudes le plus puissant. Assurez-vous qu\'il est toujours accessible.'),
  ProgramDay(day: 78, title: 'Énergie nerveuse', tip: 'Canalisez l\'énergie nerveuse dans le mouvement, pas dans la morsure.', exercise: 'La prochaine fois que vous vous sentez nerveux : secouez vigoureusement vos mains pendant 30 secondes.'),
  ProgramDay(day: 79, title: 'Soutien des pairs', tip: 'La communauté amplifie le succès. Trouvez d\'autres personnes sur le même parcours.', exercise: 'Recherchez une communauté en ligne de récupération de la morsure des ongles. Présentez-vous.'),
  ProgramDay(day: 80, title: '80 jours !', tip: 'Quatre-vingts jours de prise de conscience, d\'efforts et de croissance.', exercise: 'Offrez-vous un service professionnel de soin des ongles si possible.'),
  ProgramDay(day: 81, title: 'Assurance contre les rechutes', tip: 'Planifiez les situations à haut risque avant qu\'elles ne se produisent.', exercise: 'Listez vos 3 situations à risque le plus élevé. Rédigez une réponse spécifique pour chacune.'),
  ProgramDay(day: 82, title: 'Planification de la célébration', tip: 'Comment allez-vous célébrer le jour 90 ? Rendez-le significatif.', exercise: 'Planifiez votre célébration du jour 90 maintenant. Notez-la. Engagez-vous.'),
  ProgramDay(day: 83, title: 'Maîtrise de la boucle d\'habitude', tip: 'Signal → Routine → Récompense. Vous avez réécrit votre routine. Gardez la récompense positive.', exercise: 'Passez en revue votre nouvelle boucle d\'habitude : quel est votre signal, votre nouvelle routine et votre récompense ?'),
  ProgramDay(day: 84, title: '12 semaines !', tip: 'Trois mois d\'efforts soutenus. C\'est qui vous êtes maintenant.', exercise: 'Rédigez votre nouvelle déclaration d\'identité : "Je suis quelqu\'un qui ___" (lié au soin des ongles et à la maîtrise de soi).'),
  ProgramDay(day: 85, title: 'La dernière ligne droite', tip: 'Cinq jours restants. Restez concentré. Restez intentionnel.', exercise: 'Revisitez votre entrée du jour 1 et votre "pourquoi" initial. A-t-il évolué ?'),
  ProgramDay(day: 86, title: 'Habitudes héritées', tip: 'Les habitudes que vous construisez en 90 jours peuvent durer toute une vie si elles sont maintenues.', exercise: 'Notez vos 3 principales habitudes héritées de ce programme.'),
  ProgramDay(day: 87, title: 'Pratique de la gratitude', tip: 'La gratitude déplace l\'attention du manque à l\'abondance, réduisant les habitudes alimentées par l\'anxiété.', exercise: 'Notez 5 choses pour lesquelles vous êtes reconnaissant concernant vos mains et votre corps aujourd\'hui.'),
  ProgramDay(day: 88, title: 'Presque là', tip: 'Jour 88. La ligne d\'arrivée est en vue.', exercise: 'Faites votre rituel de soin des ongles le plus complet ce soir. Vous l\'avez mérité.'),
  ProgramDay(day: 89, title: 'La veille', tip: 'Demain est le jour 90. Ce soir, réfléchissez à votre parcours.', exercise: 'Rédigez une réflexion complète : qui vous étiez au jour 1 par rapport à aujourd\'hui.'),
  ProgramDay(day: 90, title: '90 jours ! VOUS L\'AVEZ FAIT ! 🎉', tip: 'Quatre-vingt-dix jours à choisir votre santé plutôt qu\'une habitude destructive. Vous êtes changé.', exercise: 'Prenez votre photo de comparaison finale. Partagez votre succès. Commencez votre plan de maintenance. Vous le méritez.'),
];
